 12→void ALFPTurnGameMode::StartPlay()
 13→{
 14→    // 从 GameInstance 读取战斗请求
 15→    if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
 16→    {
 17→        CachedBattleRequest = GI->ConsumeBattleRequest();
 18→        if (CachedBattleRequest.bIsValid)
 19→        {
 20→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 由世界地图触发，节点 %d, 地图 %s, 星级 %d"),
 21→                CachedBattleRequest.SourceNodeID,
 22→                *CachedBattleRequest.BattleMapName,
 23→                CachedBattleRequest.StarRating);
 24→        }
 25→    }
 26→
 27→    FActorSpawnParameters SpawnParams;
 28→    SpawnParams.Owner = this;
 29→
 30→    // 生成网格管理器
 31→    if (GridManagerClass)
 32→    {
 33→        GridManager = GetWorld()->SpawnActor<ALFPHexGridManager>(
 34→            GridManagerClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 35→    }
 36→    else
 37→    {
 38→        GridManager = GetWorld()->SpawnActor<ALFPHexGridManager>(
 39→            ALFPHexGridManager::StaticClass(), FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 40→    }
 41→
 42→    // 如果有 BattleMapName，从 CSV 加载地图
 43→    if (GridManager && !CachedBattleRequest.BattleMapName.IsEmpty())
 44→    {
 45→        FString CSVPath = FPaths::ProjectSavedDir() / TEXT("Maps") / CachedBattleRequest.BattleMapName + TEXT(".csv");
 46→        if (GridManager->LoadMapFromCSV(CSVPath))
 47→        {
 48→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 从 CSV 加载地图 %s"), *CachedBattleRequest.BattleMapName);
 49→        }
 50→        else
 51→        {
 52→            UE_LOG(LogTemp, Warning, TEXT("战斗模式: CSV 地图加载失败 %s"), *CSVPath);
 53→        }
 54→    }
 55→
 56→    // 生成回合管理器
 57→    TurnManager = GetWorld()->SpawnActor<ALFPTurnManager>(
 58→        ALFPTurnManager::StaticClass(), FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 59→
 60→    if (TurnManager)
 61→    {
 62→        TurnManager->StartGame();
 63→    }
 64→
 65→    Super::StartPlay();
 66→}
 67→
 68→void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
 69→{
 70→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 71→    if (!GI) return;
 72→
 73→    // 写回战斗结果
 74→    FLFPBattleResult Result;
 75→    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
 76→    Result.bVictory = bVictory;
 77→    Result.bEscaped = bEscaped;
 78→
 79→    // 胜利时传递捕获的单位
 80→    if (bVictory)
 81→    {
 82→        Result.CapturedUnits = CapturedUnits;
 83→    }
 84→
 85→    GI->SetBattleResult(Result);
 86→
 87→    // 返回世界地图
 88→    if (CachedBattleRequest.bIsValid)
 89→    {
 90→        GI->TransitionToWorldMap(TEXT(""));
 91→    }
 92→}
