 94→void ALFPTurnGameMode::RecordCapturedUnit(ALFPTacticsUnit* Unit)
 95→{
 96→    if (!Unit) return;
 97→
 98→    FLFPUnitEntry Entry = Unit->ToUnitEntry();
 99→    if (Entry.IsValid())
100→    {
101→        CapturedUnits.Add(Entry);
102→        UE_LOG(LogTemp, Log, TEXT("捕获单位: %s, 阶级 %d"), *Entry.TypeID.ToString(), Entry.Tier);
103→    }
104→}
