 25→void ALFPTurnManager::StartGame()
 26→{
 27→    // 收集场上所有单位（敌方预放置在关卡中）
 28→    TArray<AActor*> FoundActors;
 29→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 30→
 31→    for (AActor* Actor : FoundActors)
 32→    {
 33→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 34→        {
 35→            // 仅注册非玩家单位（玩家单位在布置阶段结束后注册）
 36→            if (Unit->GetAffiliation() != EUnitAffiliation::UA_Player)
 37→            {
 38→                TurnOrderUnits.Add(Unit);
 39→            }
 40→        }
 41→    }
 42→
 43→    // 初始化阵营 AP
 44→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 47→
 48→    // 标记为布置阶段（不广播，等 PlayerController 绑定委托后主动调用）
 49→    CurrentPhase = EBattlePhase::BP_Deployment;
 50→}
 51→
 52→void ALFPTurnManager::BeginDeploymentPhase()
 53→{
 54→    SetPhase(EBattlePhase::BP_Deployment);
 55→    UE_LOG(LogTemp, Log, TEXT("布置阶段开始"));
 56→}
 57→
 58→void ALFPTurnManager::EndDeploymentPhase()
 59→{
 60→    UE_LOG(LogTemp, Log, TEXT("布置阶段结束，注册玩家单位"));
 61→
 62→    // 收集布置阶段放置的玩家单位
 63→    TArray<AActor*> FoundActors;
 64→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 65→
 66→    for (AActor* Actor : FoundActors)
 67→    {
 68→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 69→        {
 70→            if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player && !TurnOrderUnits.Contains(Unit))
 71→            {
 72→                TurnOrderUnits.Add(Unit);
 73→            }
 74→        }
 75→    }
 76→
 77→    // 开始第一回合
 78→    BeginNewRound();
 79→}
 80→
 81→void ALFPTurnManager::BeginNewRound()
 82→{
 83→    CurrentRound++;
 84→    bIsInRound = true;
 85→
 86→    // 重置所有单位
 87→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 88→    {
 89→        if (Unit && Unit->IsValidLowLevel())
 90→        {
 91→            Unit->ResetForNewRound();
 92→        }
 93→    }
 94→
 95→    // 按速度排序单位
 96→    SortUnitsBySpeed();
 97→
 98→    // 清空上一轮的敌人计划
 99→    EnemyActionPlans.Empty();
100→    AllocatedSkills.Empty();
101→
102→    // 恢复阵营 AP
103→    for (auto& Pair : FactionCurrentAP)
104→    {
105→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
106→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
107→    }
108→
109→    // 进入敌人规划阶段
110→    BeginEnemyPlanningPhase();
111→}
112→
113→void ALFPTurnManager::EndCurrentRound()
114→{
115→    bIsInRound = false;
116→
117→    SetPhase(EBattlePhase::BP_RoundEnd);
118→
119→    // 通知玩家本回合结束
120→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
121→    {
122→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
123→        {
124→            PC->OnRoundEnded(CurrentRound);
125→        }
126→    }
127→
128→    // 添加延迟后开始新回合
129→    FTimerHandle TimerHandle;
130→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
131→}
