198→bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
199→{
200→    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
201→
202→    ALFPHexGridManager* GridManager = GetGridManager();
203→    if (!GridManager) return false;
204→
205→    // 获取当前所在的格子
206→    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
207→    if (!CurrentTile) return false;
208→
209→    // 寻找路径
210→    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
211→    // 计算路径实际移动代价（考虑地形）
212→    int32 PathCost = 0;
213→    for (ALFPHexTile* Tile : MovePath)
214→    {
215→        PathCost += Tile->GetMovementCost();
216→    }
217→    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
218→
219→    // 设置移动状态
220→    CurrentTile->SetIsOccupied(false);
221→    TargetTile = NewTargetTile;
222→    CurrentPathIndex = 0;
223→    MoveProgress = 0.0f;
224→    MovementRangeTiles.Empty();
225→
226→    // 消耗行动力
227→    //ConsumeMovePoints(1);
228→
229→    // 开始移动动画
230→    //if (MoveTimeline)
231→    //{
232→    //    MoveTimeline->PlayFromStart();
233→    //}
234→    //else
235→    //{
236→    //    // 如果没有时间线，直接完成移动
237→    //    FinishMove();
238→    //}
239→    FinishMove();
240→    //NotifyMoveComplete();
241→    return true;
242→}
