481→
482→	// 计算实际伤害（考虑防御）
483→	int32 ActualDamage = FMath::Max(Damage - Defense, 1);
484→	int32 OldHealth = CurrentHealth;
485→	CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
486→
487→	// 广播血量变化事件
488→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
489→
490→	// 蓝图事件
