622→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
623→{
624→    // 获取所有玩家单位
625→    TArray<AActor*> PlayerUnits;
626→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
627→
628→    ALFPTacticsUnit* BestTarget = nullptr;
629→    float BestThreatValue = -MAX_FLT;
630→
631→    for (AActor* Actor : PlayerUnits)
632→    {
633→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
634→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
635→        {
636→            float ThreatValue = CalculateThreatValue(Unit);
637→            if (ThreatValue > BestThreatValue)
638→            {
639→                BestThreatValue = ThreatValue;
640→                BestTarget = Unit;
641→            }
642→        }
643→    }
644→
645→    return BestTarget;
646→}
