648→ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
649→{
650→    ALFPHexGridManager* GridManager = GetGridManager();
651→    if (!GridManager)
652→    {
653→        return nullptr;
654→    }
655→    // 获取所有可移动位置
656→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
657→
658→    ALFPHexTile* BestTile = nullptr;
659→    float BestPositionValue = -MAX_FLT;
660→
661→    for (ALFPHexTile* Tile : MovementRangeTiles)
662→    {
663→        // 跳过有单位的格子
664→        if (Tile->GetUnitOnTile()) continue;
665→
666→        float PositionValue = CalculatePositionValue(Tile, Target);
667→        if (PositionValue > BestPositionValue)
668→        {
669→            BestPositionValue = PositionValue;
670→            BestTile = Tile;
671→        }
672→    }
673→
674→    return BestTile;
675→}
