677→float ALFPTacticsUnit::CalculateThreatValue(ALFPTacticsUnit* Target)
678→{
679→    // 威胁值 = 目标攻击力
680→    float ThreatValue = Target->GetAttackPower();
681→
682→    // 距离因素（越近威胁越大）
683→    int32 Distance = FLFPHexCoordinates::Distance(
684→        GetCurrentCoordinates(),
685→        Target->GetCurrentCoordinates()
686→    );
687→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
688→
689→    //// 应用行为数据
690→    //if (BehaviorData)
691→    //{
692→    //    if (BehaviorData->bPrioritizeWeakTargets)
693→    //    {
694→    //        // 增加对低血量目标的权重
695→    //        float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
696→    //        // 血量越低，威胁值越高
697→    //    }
698→
699→    //    // 应用攻击性系数
700→    //    ThreatValue *= BehaviorData->Aggressiveness;
701→    //}
702→
703→    return ThreatValue * DistanceFactor;
704→}
