761→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
762→{
763→    TArray<ALFPHexTile*> AttackRangeTiles;
764→
765→    if (ALFPHexGridManager* GridManager = GetGridManager())
766→    {
767→        // 近战攻击范围
768→        if (bMeleeAttack)
769→        {
770→            // 获取相邻格子
771→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
772→            for (const FLFPHexCoordinates& Coord : Neighbors)
773→            {
774→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
775→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
776→                {
777→                    AttackRangeTiles.Add(Tile);
778→                }
779→            }
780→        }
781→        // 远程攻击范围
782→        else
783→        {
784→            // 获取攻击范围内的所有格子
785→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
786→
787→            for (ALFPHexTile* Tile : TilesInRange)
788→            {
789→                AttackRangeTiles.Add(Tile);
790→            }
791→        }
792→    }
793→
794→    return AttackRangeTiles;
795→}
