797→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
798→{
799→    if (!Target || !Target->GetCurrentTile()) return false;
800→
801→    // 计算距离
802→    int32 Distance = FLFPHexCoordinates::Distance(
803→        CurrentCoordinates,
804→        Target->GetCurrentCoordinates()
805→    );
806→
807→    // 近战攻击判定
808→    if (bMeleeAttack)
809→    {
810→        return Distance == 1; // 相邻格子
811→    }
812→    // 远程攻击判定
813→    else
814→    {
815→        return Distance >= 2 && Distance <= AttackRange;
816→    }
817→}
