 703→bool ALFPTacticsPlayerController::AttackTarget(ALFPTacticsUnit* Attacker, ALFPTacticsUnit* Target)
 704→{
 705→    if (!Attacker || !Target || !Attacker->CanAct())
 706→    {
 707→        return false;
 708→    }
 709→
 710→    // 计算攻击代价
 711→    const int32 AttackCost = 1;
 712→
 713→    bIsAttacking = false;
 714→    CurrentControlState = EPlayControlState::MoveState;
 715→
 716→    if (!Attacker->HasEnoughActionPoints(AttackCost))
 717→    {
 718→        return false;
 719→    }
 720→
 721→    // 执行攻击逻辑
 722→    bool bAttackSucceed = Attacker->AttackTarget(Target);
 723→
 724→    if (bAttackSucceed)
 725→    {
 726→		// 消耗行动力
 727→		Attacker->ConsumeActionPoints(AttackCost);
 728→        ShowUnitRange(EUnitRange::UR_Default);
 729→    }
 730→    else
 731→    {
 732→        ShowUnitRange(EUnitRange::UR_Move);
 733→    }
 734→
 735→    // 通知回合管理器单位完成行动
 736→    if (!Attacker->HasEnoughActionPoints(1))
 737→    {
 738→		if (bAttackSucceed)
 739→		{
 740→            SkipTurn(Attacker);
 741→		}
 742→    }
 743→
 744→    return bAttackSucceed;
 745→}
