 979→void ALFPTacticsPlayerController::OnDeploymentPhaseStarted()
 980→{
 981→    bIsInDeployment = true;
 982→    bIsPlacingUnit = false;
 983→    PlacingPartyIndex = -1;
 984→    PlacingUnitPreview = nullptr;
 985→
 986→    // 获取玩家出生点并高亮
 987→    if (GridManager)
 988→    {
 989→        PlayerSpawnTiles = GridManager->GetSpawnPoints(ELFPSpawnFaction::SF_Player);
 990→        for (ALFPHexTile* Tile : PlayerSpawnTiles)
 991→        {
 992→            if (Tile)
 993→            {
 994→                Tile->SetMovementHighlight(true);
 995→            }
 996→        }
 997→    }
 998→
 999→    // 获取队伍数据
1000→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1001→    if (!GI) return;
1002→
1003→    // 初始化已布置单位数组（与 PartyUnits 等长，初始全为 nullptr）
1004→    DeployedUnits.Empty();
1005→    DeployedUnits.SetNum(GI->PartyUnits.Num());
1006→
1007→    // 创建布置 UI
1008→    if (DeploymentWidgetClass && !DeploymentWidget)
1009→    {
1010→        DeploymentWidget = CreateWidget<ULFPDeploymentWidget>(this, DeploymentWidgetClass);
1011→    }
1012→
1013→    if (DeploymentWidget)
1014→    {
1015→        DeploymentWidget->Setup(GI->PartyUnits, GI->UnitRegistry);
1016→        DeploymentWidget->OnUnitSelected.AddDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1017→        DeploymentWidget->OnConfirmPressed.AddDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1018→        DeploymentWidget->AddToViewport();
1019→    }
1020→
1021→    UE_LOG(LogTemp, Log, TEXT("布置阶段：%d 个出生点，%d 个队伍单位"),
1022→        PlayerSpawnTiles.Num(), GI->PartyUnits.Num());
1023→}
