 41→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 42→{
 43→	Super::Tick(DeltaTime);
 44→
 45→	if (bIsDragging)
 46→	{
 47→		DragTime += DeltaTime;
 48→	}
 49→
 50→	// 更新相机位置和旋转
 51→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 52→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 53→
 54→	// 相机旋转：俯视角
 55→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 56→
 57→	// 平滑插值并设置
 58→	FRotator CurrentRotation = GetControlRotation();
 59→	SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 60→
 61→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 62→	if (APawn* ControlledPawn = GetPawn())
 63→	{
 64→		FVector CurrentLocation = ControlledPawn->GetActorLocation();
 65→		ControlledPawn->SetActorLocation(
 66→			FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 67→		);
 68→	}
 69→}
