422→void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
423→{
424→	if (!BattleNode) return;
425→
426→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
427→	if (!GI) return;
428→
429→	ALFPWorldMapManager* Manager = GetWorldMapManager();
430→	if (!Manager) return;
431→
432→	// 保存世界地图快照
433→	FLFPWorldMapSnapshot Snapshot;
434→	Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
435→	if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
436→	{
437→		Snapshot.CurrentNodeID = PS->CurrentNodeID;
438→		Snapshot.CurrentTurn = PS->CurrentTurn;
439→		Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
440→		Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
441→	}
442→
443→	// 收集已触发节点
444→	for (const auto& Pair : Manager->GetNodeMap())
445→	{
446→		if (Pair.Value && Pair.Value->bHasBeenTriggered)
447→		{
448→			Snapshot.TriggeredNodeIDs.Add(Pair.Key);
449→		}
450→	}
451→
452→	GI->SaveWorldMapSnapshot(Snapshot);
453→
454→	// 设置战斗请求
455→	FLFPBattleRequest Request;
456→	Request.SourceNodeID = BattleNode->NodeID;
457→	Request.BattleMapName = BattleNode->BattleMapName;
458→	Request.StarRating = BattleNode->StarRating;
459→	Request.bCanEscape = BattleNode->bCanEscape;
460→	GI->SetBattleRequest(Request);
461→
462→	// 切换到战斗关卡
